import{_ as i,o as a,c as s,ag as c}from"./chunks/framework.CAXxHpAX.js";const y=JSON.parse('{"title":"过渡时期（新民主主义国家——社会主义国家","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-26.md","filePath":"notes/note-26.md"}'),l={name:"notes/note-26.md"};function v(r,d,o,e,n,t){return a(),s("div",null,[...d[0]||(d[0]=[c('<h1 id="过渡时期-新民主主义国家——社会主义国家" tabindex="-1">过渡时期（新民主主义国家——社会主义国家 <a class="header-anchor" href="#过渡时期-新民主主义国家——社会主义国家" aria-label="Permalink to &quot;过渡时期（新民主主义国家——社会主义国家&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、过渡时期（新民主主义国家——社会主义国家）时间：</span>1949-1956年</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、社会主义制度的建立（社会主义初级阶段）标志：</span>1956年三大改造完成</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、全面建设社会主义十年时间：</span>1956-1966年</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、农村经济体制改革：</span>家庭联产承包责任制、包干到户、自负盈亏</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、两弹一星：</span>核弹（原子弹、氢弹）导弹和人造地球卫星</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、探索建设社会主义道路的良好开端：</span>中共八大</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、开始改变工业落后的面貌，向社会主义工业化迈进：</span>一五计划。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、三大改造：</span>农业和手工业：生产合作社；资本主义工商业：赎买政策、公私合营</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、巩固新生政权三件大事：</span>西藏和平解放、土地改革、抗美援朝</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">0、充当临时宪法作用的是：</span>《共同纲领》</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、一五计划时间和特点：</span>1953-1957，优先发展重工业</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>2、1961年，八字方针是？调整、巩固、充实、提高。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、城市经济体制改革的中心环节：</span>增强企业活力</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、1949-1956年：</span>过渡时期（新民主主义国家——社会主义国家）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、社会主义制度的建立（社会主义初级阶段）：</span>1956年三大改造完成</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、社会主义建设的探索：</span>1956-1976年（1956-1966年全面建设社会主义十年）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、1956-1966年全面建设社会主义十年成就：</span>大庆、胜利油田；兰新、兰青、包兰铁路、人工合成结晶牛胰岛素；1964，原子弹试验成功</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、1966-1976年文革建设成就：</span>1966，导弹实验成功；1967，氢弹实验成功；1970，发射人造地球卫星——东方红一号；1973，袁隆平，籼型杂交水稻。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、两弹一星：</span>核弹（原子弹、氢弹）导弹和人造地球卫星</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、中共八大：</span>1956年，分析主要矛盾，任务：落后农业国——先进工业国；探索建设社会主义道路的良好开端。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、社会主义建设成就的影响：</span>初步形成了独立的、比较完整的工业体系和国民经济体系，为现代化建设打下了坚实的物质基础。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、开始改变工业落后的面貌，向社会主义工业化迈进：</span>一五计划。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">0、三大改造的实质和意义：</span>实现生产资料私有制向社会主义公有制转变；标志着社会主义基本制度在我国建立，进入社会主义初级阶段。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">鸦片战争的影响：</span>1840-1842，中国丧失了完整独立的主权，开始沦为半殖民地半封建社会。是中国近代史的开端。自然经济遭到破坏。刺激一些官员开始了解国际形势。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">第二次鸦片战争影响：</span>1856-1860，半殖民地化程度进一步加深，西方侵略势力由沿海深入长江中下游地区，俄国占领北方大片领土。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">甲午中日战争：</span>1894-1895，侵略势力进一步深入中国腹地，大大加深了中国半殖民地化程度，刺激列强嫌弃瓜分中国狂潮，进一步加剧民族危机。及其中华民族觉醒，推动中国人民展开救亡图存斗争（百日维新、实业救国）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">八国联军侵华：</span>清政府沦为帝国主义列强统治中国的工具；中国完全陷入半殖民地半封建社会。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、中共诞生的意义：</span>是中国历史上开天辟地的大事变，自从有了中国共产党，中国革命面貌就焕然一新。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、南昌起义的意义：</span>打响了武装反抗国民党反动派的第一枪，标志着中共独立领导革命战争、创建人民军队和武装夺取政权的开端。</p></div><div class="circle-overlay"></div></div></div>',35)])])}const b=i(l,[["render",v]]);export{y as __pageData,b as default};
